import type { Feature, MultiPolygon, Polygon, Position } from 'geojson';

type LatLngCoordinate = [number, number];
type LatLngRing = LatLngCoordinate[];
type LatLngPolygon = LatLngRing[];

const coordinatesMatch = (left: Position, right: Position): boolean =>
  left.length === right.length && left.every((value, index) => value === right[index]);

const toGeoJsonRing = (ring: LatLngRing): Position[] => {
  const converted = ring.map(([lat, lng]) => [lng, lat]);
  const first = converted[0];
  const last = converted[converted.length - 1];

  if (!first || !last || coordinatesMatch(first, last)) {
    return converted;
  }

  return [...converted, [...first]];
};

const toGeoJsonMultiPolygon = (polygons: LatLngPolygon[]): MultiPolygon['coordinates'] =>
  polygons.map((polygon) => polygon.map(toGeoJsonRing));

